"""原型驗證 richData 儲存格圖片抽取鏈，跑出 (sheet, cell, media) 清單。"""
import zipfile
import re
from xml.etree import ElementTree as ET

R_NS = "{http://schemas.openxmlformats.org/officeDocument/2006/relationships}"
PKG_REL = "{http://schemas.openxmlformats.org/package/2006/relationships}Relationship"


def local(el):
    return el.tag.split("}")[-1] if "}" in el.tag else el.tag


def get_sheet_names(z):
    names = {}
    root = ET.fromstring(z.read("xl/workbook.xml").decode("utf-8"))
    ns = {"s": "http://schemas.openxmlformats.org/spreadsheetml/2006/main"}
    sheets = root.find("s:sheets", ns)
    for i, sh in enumerate(sheets.findall("s:sheet", ns), start=1):
        names[i] = sh.get("name", f"Sheet{i}")
    return names


def run(path):
    results = []
    with zipfile.ZipFile(path) as z:
        names = set(z.namelist())
        needed = [
            "xl/metadata.xml", "xl/richData/rdrichvalue.xml",
            "xl/richData/rdrichvaluestructure.xml",
            "xl/richData/richValueRel.xml",
            "xl/richData/_rels/richValueRel.xml.rels",
        ]
        if not all(n in names for n in needed):
            print("缺 richData 檔，無儲存格圖片")
            return results

        # A. 結構：structure index -> LocalImageIdentifier 欄位序
        struct_root = ET.fromstring(z.read("xl/richData/rdrichvaluestructure.xml").decode("utf-8"))
        local_img_field = {}
        for s_idx, s in enumerate(struct_root):
            for k_idx, k in enumerate(s):
                if k.get("n") == "_rvRel:LocalImageIdentifier":
                    local_img_field[s_idx] = k_idx
                    break

        # B. rich value index -> richValueRel 位置
        rv_root = ET.fromstring(z.read("xl/richData/rdrichvalue.xml").decode("utf-8"))
        rv_to_relpos = {}
        for rv_idx, rv in enumerate(rv_root):
            s_idx = int(rv.get("s", -1))
            if s_idx not in local_img_field:
                continue
            vs = [c for c in rv if local(c) == "v"]
            fi = local_img_field[s_idx]
            if fi < len(vs) and vs[fi].text is not None:
                rv_to_relpos[rv_idx] = int(vs[fi].text)

        # C. rel 位置 -> rId
        rvr_root = ET.fromstring(z.read("xl/richData/richValueRel.xml").decode("utf-8"))
        relpos_to_rid = {p: rel.get(R_NS + "id") for p, rel in enumerate(rvr_root)}

        # D. rId -> media
        rels_root = ET.fromstring(z.read("xl/richData/_rels/richValueRel.xml.rels").decode("utf-8"))
        rid_to_media = {}
        for rel in rels_root.findall(PKG_REL):
            tgt = rel.get("Target", "")
            img = "xl/" + tgt[3:] if tgt.startswith("../") else tgt
            rid_to_media[rel.get("Id")] = img

        # E. metadata.xml: types / futureMetadata / valueMetadata
        md_root = ET.fromstring(z.read("xl/metadata.xml").decode("utf-8"))
        type_index, future, value_meta = {}, {}, []
        for child in md_root:
            lc = local(child)
            if lc == "metadataTypes":
                for i, mt in enumerate(child, start=1):
                    type_index[mt.get("name")] = i
            elif lc == "futureMetadata":
                lst = []
                for bk in child:
                    rvb = next((int(e.get("i")) for e in bk.iter() if local(e) == "rvb"), None)
                    lst.append(rvb)
                future[child.get("name")] = lst
            elif lc == "valueMetadata":
                for bk in child:
                    rc = next((e for e in bk.iter() if local(e) == "rc"), None)
                    value_meta.append((int(rc.get("t")), int(rc.get("v"))) if rc is not None else None)

        def vm_to_media(vm):
            idx = vm - 1
            if not (0 <= idx < len(value_meta)) or value_meta[idx] is None:
                return None
            t, v = value_meta[idx]
            if type_index.get("XLRICHVALUE") != t:
                return None
            rvb_list = future.get("XLRICHVALUE", [])
            if not (0 <= v < len(rvb_list)):
                return None
            rich_idx = rvb_list[v]
            if rich_idx is None or rich_idx not in rv_to_relpos:
                return None
            rid = relpos_to_rid.get(rv_to_relpos[rich_idx])
            return rid_to_media.get(rid) if rid else None

        # F. 各 sheet 掃 vm cells
        sheet_names = get_sheet_names(z)
        for n in range(1, len(sheet_names) + 1):
            sx = f"xl/worksheets/sheet{n}.xml"
            if sx not in names:
                continue
            s = z.read(sx).decode("utf-8", "ignore")
            for cell, vm in re.findall(r'<c r="([A-Z]+\d+)"[^>]*\svm="(\d+)"', s):
                media = vm_to_media(int(vm))
                if media:
                    results.append((sheet_names[n], cell, media))
    return results


path = r"G:\AI\excel-to-ai-document\output\Eye Strike2 規格書\source\Eye Strike2 規格書.xlsx"
out = run(path)
print("總計儲存格圖片:", len(out))
for sheet, cell, media in out:
    print(f"  {sheet} [{cell}] -> {media}")

