        for s_idx, s in enumerate(struct_root):
            for k_idx, k in enumerate(s):
                if k.get("n") == "_rvRel:LocalImageIdentifier":
                    local_img_field[s_idx] = k_idx
                    break

        # B. rich value index → richValueRel 位置（讀該 rv 的 LocalImageIdentifier 欄值）
        rv_root = ET.fromstring(z.read("xl/richData/rdrichvalue.xml").decode("utf-8"))
        rv_to_relpos = {}
        for rv_idx, rv in enumerate(rv_root):
            s_idx = int(rv.get("s", -1))
            if s_idx not in local_img_field:
                continue
            vs = [c for c in rv if _strip_ns(c.tag) == "v"]
            fi = local_img_field[s_idx]
            if fi < len(vs) and vs[fi].text is not None:
                rv_to_relpos[rv_idx] = int(vs[fi].text)

        # C. richValueRel 位置 → rId
        rvr_root = ET.fromstring(z.read("xl/richData/richValueRel.xml").decode("utf-8"))
        rid_attr = "{http://schemas.openxmlformats.org/officeDocument/2006/relationships}id"
        relpos_to_rid = {p: rel.get(rid_attr) for p, rel in enumerate(rvr_root)}

        # D. rId → media 路徑
        rels_root = ET.fromstring(z.read("xl/richData/_rels/richValueRel.xml.rels").decode("utf-8"))
        pkg_rel = "{http://schemas.openxmlformats.org/package/2006/relationships}Relationship"
        rid_to_media = {}
        for rel in rels_root.findall(pkg_rel):
            tgt = rel.get("Target", "")
            rid_to_media[rel.get("Id")] = "xl/" + tgt[3:] if tgt.startswith("../") else tgt

        # E. metadata.xml：metadataTypes / futureMetadata / valueMetadata
        md_root = ET.fromstring(z.read("xl/metadata.xml").decode("utf-8"))
        type_index, future, value_meta = {}, {}, []
        for child in md_root:
            lc = _strip_ns(child.tag)
            if lc == "metadataTypes":
                for i, mt in enumerate(child, start=1):  # t 屬性為 1-based
                    type_index[mt.get("name")] = i
            elif lc == "futureMetadata":
                rvbs = []
                for bk in child:
                    rvbs.append(next(
                        (int(e.get("i")) for e in bk.iter() if _strip_ns(e.tag) == "rvb"), None))
                future[child.get("name")] = rvbs
            elif lc == "valueMetadata":
                for bk in child:
                    rc = next((e for e in bk.iter() if _strip_ns(e.tag) == "rc"), None)
                    value_meta.append(
                        (int(rc.get("t")), int(rc.get("v"))) if rc is not None else None)

        def _vm_to_media(vm: int):
            idx = vm - 1  # vm 屬性為 1-based
            if not (0 <= idx < len(value_meta)) or value_meta[idx] is None:
                return None
            t, v = value_meta[idx]
            if type_index.get("XLRICHVALUE") != t:
                return None  # 此 vm 非圖片型 rich value
            rvb_list = future.get("XLRICHVALUE", [])
            if not (0 <= v < len(rvb_list)):
                return None
            rich_idx = rvb_list[v]
            if rich_idx is None or rich_idx not in rv_to_relpos:
                return None
            rid = relpos_to_rid.get(rv_to_relpos[rich_idx])
            return rid_to_media.get(rid) if rid else None

        # F. 各 sheet 掃描帶 vm= 的儲存格，沿鏈解出 media
        sheet_names = _get_sheet_names(z)
        for idx, sheet_name in sheet_names.items():
            sx = f"xl/worksheets/sheet{idx}.xml"
            if sx not in names:
                continue
            sheet_xml = z.read(sx).decode("utf-8", "ignore")
            for cell, vm in re.findall(r'<c r="([A-Z]+\d+)"[^>]*\svm="(\d+)"', sheet_xml):
                img_path = _vm_to_media(int(vm))
                if img_path:
                    results.append({
                        "sheet": sheet_name,
                        "cell": cell,
                        "image_path_in_zip": img_path,
                    })
    return results


